/**
 * @fileoverview 游戏状态 Store Adapter
 * @module stores/gameStore
 * 
 * 适配层：持有领域对象 (Game, Sudoku)，对外暴露响应式状态和方法
 * 
 * 响应式状态：
 *   - grid: 当前数独局面
 *   - fixed: 固定格子掩码
 *   - invalidCells: 冲突单元格
 *   - gameWon: 游戏是否胜利
 *   - gamePaused: 游戏是否暂停
 * 
 * 命令方法：
 *   - startNew(difficulty): 开始新游戏
 *   - startCustom(sencode): 从编码开始游戏
 *   - guess(pos, value): 用户猜测
 *   - undo(): 撤销
 *   - redo(): 重做
 *   - pause(): 暂停
 *   - resume(): 继续
 */

import { BOX_SIZE, SUDOKU_SIZE } from '@sudoku/constants';
import { generateSudoku, solveSudoku } from '@sudoku/sudoku';
import { derived, writable } from 'svelte/store';
import { decodeSencode } from '@sudoku/sencode';
import { hints } from '@sudoku/stores/hints';
import { Game, createGame } from '../../../domain/Game.js';
import { Sudoku, createSudoku } from '../../../domain/Sudoku.js';
import { Move } from '../../../domain/Move.js';

/** @type {Game|null} 当前 Game 实例 */
let currentGame = null;

/** @type {import('svelte/store').Writable<number[][]>} gridStore */
const gridStore = writable(createEmptyGrid());

/** @type {import('svelte/store').Writable<boolean[][]>} fixedStore */
const fixedStore = writable(createEmptyFixed());

/** @type {import('svelte/store').Writable<boolean>} gamePausedStore */
const gamePausedStore = writable(true);

/**
 * 计算冲突单元格
 * @param {number[][]} $grid 9x9 数独棋盘
 * @returns {string[]} 冲突单元格坐标数组，如 ['0,0', '1,2']
 */
function calculateInvalidCells($grid) {
    /** @type {string[]} */
    const _invalidCells = [];

    /**
     * @param {number} x
     * @param {number} y
     */
    const addInvalid = (x, y) => {
        const xy = x + ',' + y;
        if (!_invalidCells.includes(xy)) _invalidCells.push(xy);
    };

    for (let y = 0; y < SUDOKU_SIZE; y++) {
        for (let x = 0; x < SUDOKU_SIZE; x++) {
            const value = $grid[y][x];

            if (value) {
                // 检查行
                for (let i = 0; i < SUDOKU_SIZE; i++) {
                    if (i !== x && $grid[y][i] === value) {
                        addInvalid(x, y);
                    }
                }

                // 检查列
                for (let i = 0; i < SUDOKU_SIZE; i++) {
                    if (i !== y && $grid[i][x] === value) {
                        addInvalid(x, i);
                    }
                }

                // 检查 3x3 宫格
                const startY = Math.floor(y / BOX_SIZE) * BOX_SIZE;
                const endY = startY + BOX_SIZE;
                const startX = Math.floor(x / BOX_SIZE) * BOX_SIZE;
                const endX = startX + BOX_SIZE;
                for (let row = startY; row < endY; row++) {
                    for (let col = startX; col < endX; col++) {
                        if (row !== y && col !== x && $grid[row][col] === value) {
                            addInvalid(col, row);
                        }
                    }
                }
            }
        }
    }

    return _invalidCells;
}

/** @type {import('svelte/store').Readable<string[]>} 冲突单元格 */
export const invalidCells = derived(gridStore, ($grid) => {
    return calculateInvalidCells($grid);
}, []);

/** @type {import('svelte/store').Readable<boolean>} 游戏是否胜利 */
export const gameWon = derived(
    [gridStore, invalidCells],
    ([$grid, $invalidCells]) => {
        for (let row = 0; row < SUDOKU_SIZE; row++) {
            for (let col = 0; col < SUDOKU_SIZE; col++) {
                if ($grid[row][col] === 0) return false;
            }
        }
        return $invalidCells.length === 0;
    },
    false,
);

/**
 * 将领域对象的状态同步到响应式 Store
 */
function syncToStore() {
    if (!currentGame) return;
    
    const sudoku = currentGame.getSudoku();
    const grid = sudoku.getGrid();
    const fixed = sudoku.getFixed();
    
    gridStore.set(grid.map(row => [...row]));
    fixedStore.set(fixed.map(row => [...row]));
}

/**
 * 开始新游戏
 * @param {string} [difficulty='easy'] 难度级别
 */
function startNew(difficulty = 'easy') {
    const puzzleGrid = generateSudoku(difficulty);
    const sudoku = createSudoku(puzzleGrid);
    currentGame = createGame({ sudoku });
    syncToStore();
    gamePausedStore.set(false);
}

/**
 * 从 Sencode 开始自定义游戏
 * @param {string} sencode
 */
function startCustom(sencode) {
    const grid = decodeSencode(sencode);
    const sudoku = createSudoku(grid);
    currentGame = createGame({ sudoku });
    syncToStore();
    gamePausedStore.set(false);
}

/**
 * 用户猜测（填入数字）
 * @param {{x: number, y: number}} pos 位置 (x: 列索引, y: 行索引)
 * @param {number} value 填入的值 [1-9]
 */
function guess(pos, value) {
    if (!currentGame) return;
    
    const move = new Move({
        row: pos.y,
        col: pos.x,
        value: value
    });
    
    currentGame.guess(move);
    syncToStore();
}

/** 撤销 */
function undo() {
    if (!currentGame) return;
    currentGame.undo();
    syncToStore();
}

/** 重做 */
function redo() {
    if (!currentGame) return;
    currentGame.redo();
    syncToStore();
}

/** 暂停游戏 */
function pause() {
    gamePausedStore.set(true);
}

/** 继续游戏 */
function resume() {
    gamePausedStore.set(false);
}

/**
 * @returns {number[][]} 9x9 全零棋盘
 */
function createEmptyGrid() {
    return Array(9).fill(null).map(() => Array(9).fill(0));
}

/**
 * @returns {boolean[][]} 9x9 全 false 数组
 */
function createEmptyFixed() {
    return Array(9).fill(null).map(() => Array(9).fill(false));
}

/**
 * 游戏状态 Store Adapter
 * 
 * 响应式状态：
 *   - grid: 当前数独局面
 *   - fixed: 固定格子掩码
 *   - gamePaused: 游戏是否暂停
 *   - invalidCells: 冲突单元格（派生）
 *   - gameWon: 游戏是否胜利（派生）
 * 
 * 命令方法：
 *   - startNew(difficulty): 开始新游戏
 *   - startCustom(sencode): 从编码开始游戏
 *   - guess(pos, value): 用户猜测
 *   - undo(): 撤销
 *   - redo(): 重做
 *   - pause(): 暂停
 *   - resume(): 继续
 */
export const gameStore = {
    /**
     * 组合订阅接口
     * @param {(value: {grid: number[][], fixed: boolean[][], gamePaused: boolean}) => void} callback
     * @returns {() => void}
     */
    subscribe: (callback) => {
        /** @type {{grid: number[][], fixed: boolean[][], gamePaused: boolean}|null} */
        let currentValue = null;
        
        const update = () => {
            /** @type {number[][]} */
            let grid;
            /** @type {boolean[][]} */
            let fixed;
            /** @type {boolean} */
            let gamePaused;
            gridStore.subscribe(g => grid = g)();
            fixedStore.subscribe(f => fixed = f)();
            gamePausedStore.subscribe(p => gamePaused = p)();
            
            const newValue = { grid, fixed, gamePaused };
            currentValue = newValue;
            callback(newValue);
        };
        
        const unsubGrid = gridStore.subscribe(() => update());
        const unsubFixed = fixedStore.subscribe(() => update());
        const unsubPaused = gamePausedStore.subscribe(() => update());
        
        update();
        
        return () => {
            unsubGrid();
            unsubFixed();
            unsubPaused();
        };
    },
    
    /** 单独订阅 grid */
    grid: {
        subscribe: gridStore.subscribe
    },
    
    /** 单独订阅 fixed */
    fixed: {
        subscribe: fixedStore.subscribe
    },
    
    /** 单独订阅 gamePaused */
    gamePaused: {
        subscribe: gamePausedStore.subscribe
    },
    
    /** 派生状态 */
    invalidCells,
    gameWon,
    
    /** 命令方法 */
    startNew,
    startCustom,
    guess,
    undo,
    redo,
    pause,
    resume,
    
    /**
     * @param {number[][]} gridData
     * @param {number} x 列索引 [0-8]
     * @param {number} y 行索引 [0-8]
     * @returns {number}
     */
    get(gridData, x, y) {
        return gridData[y][x];
    },
    
    /**
     * @param {boolean[][]} fixedData
     * @param {number} x 列索引 [0-8]
     * @param {number} y 行索引 [0-8]
     * @returns {boolean}
     */
    isFixedAt(fixedData, x, y) {
        return fixedData[y][x];
    },
    
    /**
     * 应用提示（填入正确数字）
     * @param {{x: number, y: number}} pos 位置
     */
    applyHint(pos) {
        if (!currentGame) return;

        hints.useHint();

        /** @type {number[][]} */
        let currentGrid;
        gridStore.subscribe(g => currentGrid = g)();

        try {
            const solved = solveSudoku(currentGrid);
            const correctValue = solved[pos.y][pos.x];

            const move = new Move({
                row: pos.y,
                col: pos.x,
                value: correctValue
            });
            currentGame.guess(move);
            syncToStore();
        } catch (e) {
            console.warn('[applyHint] Cannot solve:', e.message);
        }
    }
};

export default gameStore;
